const fs = require("fs");
const yaml = require("js-yaml");
const { execSync } = require("child_process");
const path = require("path");

const KMS_API_FILE = "./kms_api.yml";
const WALLET_API_FILE = "./wallet_api.yaml";
const COMBINED_API_FILE = "./combined_api.yaml";

function combineOpenAPISpecs() {
  console.log("Combining OpenAPI specifications...");

  // Read KMS API spec
  const kmsApiContent = fs.readFileSync(KMS_API_FILE, "utf8");
  const kmsApi = yaml.load(kmsApiContent);

  // Check if wallet API file exists
  if (!fs.existsSync(WALLET_API_FILE)) {
    console.log(`${WALLET_API_FILE} not found. Using only ${KMS_API_FILE}`);
    return kmsApi;
  }

  // Read Wallet API spec
  const walletApiContent = fs.readFileSync(WALLET_API_FILE, "utf8");
  const walletApi = yaml.load(walletApiContent);

  // Combine the specs
  const combinedApi = {
    ...kmsApi,
    paths: {
      ...kmsApi.paths,
      ...walletApi.paths,
    },
    // Dynamically merge all components subkeys
    components: Object.keys({
      ...(kmsApi.components || {}),
      ...(walletApi.components || {}),
    }).reduce((mergedComponents, key) => {
      mergedComponents[key] = {
        ...(kmsApi.components?.[key] || {}),
        ...(walletApi.components?.[key] || {}),
      };
      return mergedComponents;
    }, {}),
  };

  // Merge tags if they exist
  if (walletApi.tags || kmsApi.tags) {
    const existingTags = new Set((kmsApi.tags || []).map(tag => tag.name));
    const newTags = (walletApi.tags || []).filter(tag => !existingTags.has(tag.name));
    combinedApi.tags = [...(kmsApi.tags || []), ...newTags];
  }

  return combinedApi;
}

function generateClient() {
  try {
    // Combine the API specs
    const combinedSpec = combineOpenAPISpecs();

    // Write combined spec to file
    const combinedYaml = yaml.dump(combinedSpec, {
      lineWidth: -1,
      noRefs: true,
    });
    fs.writeFileSync(COMBINED_API_FILE, combinedYaml);
    console.log(`Combined API spec written to ${COMBINED_API_FILE}`);

    // Run OpenAPI generator
    console.log("Running OpenAPI generator...");
    const generateCommand = `npx @openapitools/openapi-generator-cli generate --skip-validate-spec -i "${COMBINED_API_FILE}" -g typescript-axios -o . -c openapi-config.json`;
    execSync(generateCommand, { stdio: "inherit" });

    // Run prettier (optional - don't fail if prettier has issues)
    console.log("Formatting generated code...");
    try {
      // First check if prettier exists locally
      const prettierPath = path.join(__dirname, "node_modules", ".bin", "prettier");
      if (fs.existsSync(prettierPath)) {
        execSync(`"${prettierPath}" --write "**/*.ts"`, { stdio: "inherit" });
      } else {
        // Try npx
        execSync('npx --no-install prettier --write "**/*.ts" 2>/dev/null || true', {
          stdio: "inherit",
          shell: true,
        });
      }
      console.log("Code formatted successfully!");
    } catch (prettierError) {
      console.warn(
        'Note: Prettier formatting was skipped. You can format manually with: npx prettier --write "**/*.ts"',
      );
    }

    // Clean up combined file
    console.log("Cleaning up temporary files...");
    fs.unlinkSync(COMBINED_API_FILE);
    console.log("Generation complete!");
  } catch (error) {
    console.error("Error during generation:", error.message);

    // Clean up on error
    if (fs.existsSync(COMBINED_API_FILE)) {
      fs.unlinkSync(COMBINED_API_FILE);
    }

    process.exit(1);
  }
}

// Run the generation
generateClient();
